/**
 * validate_output.js — AI 输出话术自动扫描
 *
 * 扫描 AI 草拟的回复话术，标记潜在风险点。
 * 不拦截输出，只标记提醒。用户是最终决定者。
 *
 * 用法:
 *   echo "回复文本" | node scripts/validate_output.js [--cid=<cid>]
 *   node scripts/validate_output.js --file=<path> [--cid=<cid>]
 *
 * 检测项:
 *   1. 具体金额 → 提醒确认
 *   2. 日期承诺 → 提醒确认
 *   3. 语言与客户最后消息不一致 → 提醒
 *   4. MOQ/数量决定 → 提醒确认
 *   5. 我方延迟回复 >24h 且未致歉 → 提醒
 */

const fs = require("fs");
const path = require("path");

// ── 参数解析 ──────────────────────────────────────────────
const args = process.argv.slice(2);
const getArg = (name) => {
  const prefix = `--${name}=`;
  const found = args.find((a) => a.startsWith(prefix));
  return found ? found.slice(prefix.length) : null;
};

const cid = getArg("cid");
const filePath = getArg("file");

// ── 读取输入 ──────────────────────────────────────────────
let inputText = "";

if (filePath) {
  if (!fs.existsSync(filePath)) {
    console.error(`文件不存在: ${filePath}`);
    process.exit(1);
  }
  inputText = fs.readFileSync(filePath, "utf-8");
} else {
  // 从 stdin 读取
  inputText = fs.readFileSync(0, "utf-8"); // fd 0 = stdin
}

if (!inputText.trim()) {
  console.error("未检测到输入文本。用法: echo '回复内容' | node validate_output.js");
  process.exit(1);
}

// ── 规则库 ────────────────────────────────────────────────

const findings = [];

