let contextInfo = null;
if (cid) {
  contextInfo = getContextInfo(cid);
  if (contextInfo) {
    // 3. 语言一致性检查
    if (contextInfo.customerLang) {
      const inputLang = detectLanguage(inputText);
      if (inputLang && inputLang !== contextInfo.customerLang && inputLang !== "mixed") {
        findings.push({
          type: "语言不一致",
          severity: "⚠",
          detail: `客户最后消息语言: ${contextInfo.customerLang === "fr" ? "法语" : contextInfo.customerLang === "ar" ? "阿拉伯语" : contextInfo.customerLang === "en" ? "英语" : contextInfo.customerLang === "zh" ? "中文" : contextInfo.customerLang}，AI 输出语言: ${inputLang === "en" ? "英语" : inputLang === "zh" ? "中文" : inputLang} → 请确认是否需要调整`,
          source: "rule:lang",
        });
      }
    }

    // 5. 延迟致歉检测
    if (contextInfo.hoursSinceOurLast > 24) {
      const hasApology = /sorry|apologize|apology|抱歉|对不起|不好意思|致歉|迟[了到]|晚[了回]复|回复.*晚|回复.*迟/i;
