  { pattern: /within\s+\d+\s*(day|week|month|hour|business\s*day)/gi, desc: "英文时间承诺 (within X days)" },
  { pattern: /in\s+\d+\s*(day|week|month|hour)/gi, desc: "英文时间承诺 (in X days)" },
  { pattern: /\b\d+\s*(day|week|month|hour)\b/gi, desc: "英文时间承诺 (X days)" },
