    // 找我方最后一条消息的时间（最新在前，从索引 0 开始）
    let ourLastTime = null;
    for (let i = 0; i < realMsgs.length; i++) {
      const uid = realMsgs[i].message?.sender?.uid || "";
      if (uid.includes("2500000853693")) {
        ourLastTime = realMsgs[i].message?.createAt || null;
        break;
      }
    }

    const hoursSinceOurLast = ourLastTime
      ? (Date.now() - ourLastTime) / (1000 * 60 * 60)
      : null;

    return {
      name: raw.name || null,
      customerLang,
      ourLastTime,
      hoursSinceOurLast,
    };
  } catch (e) {
    return null;
  }
}

function detectLanguage(text) {
  if (!text || !text.trim()) return null;

  // 统计各类字符
  let cjk = 0;
  let arabic = 0;
  let french = 0;
  let latin = 0;

  for (const ch of text) {
    const code = ch.charCodeAt(0);
    if ((code >= 0x4E00 && code <= 0x9FFF) || (code >= 0x3400 && code <= 0x4DBF)) {
      cjk++;
    } else if (code >= 0x0600 && code <= 0x06FF) {
      arabic++;
    } else if (code >= 0x0041 && code <= 0x007A) {
      latin++;
      // 法语特征词
      if (/[eèéêë]/.test(ch)) french++;
    }
  }

  const total = cjk + arabic + latin;
  if (total === 0) return null;

  if (cjk / total > 0.15) return "zh";
  if (arabic / total > 0.10) return "ar";

  // 法语特征词检测
  const frenchWords = /\b(je|tu|nous|vous|le|la|les|est|sont|dans|pour|avec|sur|pas|une|très|bien|merci|bonjour|salut|comment|pourquoi|quand|quoi|parce|aussi|mais|dans|peut|faire|avoir|être|aller|pouvoir|devoir|vouloir|celui|celle|ceux|mon|ton|son|notre|votre|leur)\b/gi;
  const frenchMatch = text.match(frenchWords);
  if (frenchMatch && frenchMatch.length >= 2) return "fr";

  if (latin / total > 0.5) return "en";

  return "mixed";
}
