// Run scan pointing to temp dir
const fs = require('fs');
const path = require('path');

// Replicate scan logic with temp dir
const BRIEFS_DIR = '/tmp/test_briefs';
const CHAT_DIR = path.resolve('./data/chat_history');

function cidToFilename(cidStr) {
  const match = cidStr.match(/^(.+)#(\d+)@(\w+)$/);
  if (!match) return null;
  const [, left, channel, platform] = match;
  return left + '_' + channel + '_' + platform + '.json';
}

function parseFrontmatter(content) {
  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!match) return null;
  const fm = {};
  for (const line of match[1].split('\n')) {
    const kv = line.match(/^(\w+):\s*(.+)$/);
    if (kv) fm[kv[1]] = kv[2].trim();
  }
  return fm;
}

const files = fs.readdirSync(BRIEFS_DIR).filter(f => f.endsWith('.md'));
for (const file of files) {
  const content = fs.readFileSync(path.join(BRIEFS_DIR, file), 'utf8');
  const fm = parseFrontmatter(content);
  if (!fm) continue;
  const days = Math.round((Date.now() - new Date(fm.checked + 'T00:00:00Z').getTime()) / 86400000);
  const chatFile = cidToFilename(fm.cid);
  const chatPath = chatFile ? path.join(CHAT_DIR, chatFile) : null;
  let latestMsg = 'N/A';
  let hasNew = false;
  if (chatPath && fs.existsSync(chatPath)) {
    const raw = JSON.parse(fs.readFileSync(chatPath, 'utf8'));
    if (raw.messages?.[0]) {
      const ts = raw.messages[0].message?.createAt;
      latestMsg = new Date(ts).toISOString().slice(0,10);
      hasNew = ts > new Date(fm.checked + 'T00:00:00Z').getTime();
    }
  }
  const flags = [];
  if (hasNew) flags.push('有新消息');
  if (fm.heat === 'NOW' && days > 7) flags.push('过期' + days + '天未检查');
  if (fm.heat === 'SOON' && days > 30) flags.push('可能过期');
  console.log(fm.heat.padEnd(5) + ' | checked:' + fm.checked + ' | ' + days + '天 | 最新:' + latestMsg + ' | ' + (flags.join(', ') || '正常'));
}
"

