const fs = require('fs');
const path = require('path');

// Test stale detection with in-memory date simulation
const BRIEFS_DIR = './data/briefs';
const CHAT_DIR = './data/chat_history';

function cidToFilename(cidStr) {
  const match = cidStr.match(/^(.+)#(\d+)@(\w+)\$/);
  if (!match) return null;
  const [, left, channel, platform] = match;
  return left + '_' + channel + '_' + platform + '.json';
}

function parseFrontmatter(content) {
  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!match) return null;
  const fm = {};
  for (const line of match[1].split('\n')) {
    const kv = line.match(/^(\w+):\s*(.+)\$/);
    if (kv) fm[kv[1]] = kv[2].trim();
  }
  return fm;
}

const files = fs.readdirSync(BRIEFS_DIR).filter(f => f.endsWith('.md'));
console.log('过期/陈旧检测测试 (模拟不同checked日期):\n');

const tests = [
  { checked: '2026-05-15', desc: '刚刚检查' },
  { checked: '2026-05-01', desc: '15天前检查' },
  { checked: '2026-03-01', desc: '76天前检查' },
];

const NOW_STALE = 7;
const SOON_STALE = 30;

for (const test of tests) {
  console.log('── 模拟: checked = ' + test.checked + ' (' + test.desc + ') ──');
  for (const file of files) {
    const content = fs.readFileSync(path.join(BRIEFS_DIR, file), 'utf8');
    const fm = parseFrontmatter(content);
    if (!fm || !fm.cid) continue;
    const days = Math.round((Date.now() - new Date(test.checked + 'T00:00:00Z').getTime()) / 86400000);
    const chatFile = cidToFilename(fm.cid);
    const chatPath = chatFile ? path.join(CHAT_DIR, chatFile) : null;
    let hasNew = false;
    if (chatPath && fs.existsSync(chatPath)) {
      const raw = JSON.parse(fs.readFileSync(chatPath, 'utf8'));
      if (raw.messages?.[0]) {
        hasNew = raw.messages[0].message?.createAt > new Date(test.checked + 'T00:00:00Z').getTime();
      }
    }
    const flags = [];
    if (hasNew) flags.push('有新消息');
    if (fm.heat === 'NOW' && days > NOW_STALE) flags.push('过期' + days + '天未检查');
    if (fm.heat === 'SOON' && days > SOON_STALE) flags.push('可能过期');
    console.log('  ' + fm.heat.padEnd(5) + ' ' + file.substring(0,35).padEnd(37) + ' ' + String(days).padStart(3) + '天 → ' + (flags.join(', ') || '正常'));
  }
  console.log('');
}
"

