#!/usr/bin/env node
/**
 * batch_gen_briefs.js — 批量生成状态卡草稿
 *
 * 从 heat_classification.json 读取 NOW 客户列表，
 * 读取聊天记录最后 20 条消息，自动生成状态卡。
 *
 * 所有 AI 生成的摘要字段标注"初稿"。
 */

const fs = require("fs");
const path = require("path");

const DATA_DIR = path.resolve(__dirname, "..", "data");
const CHAT_DIR = path.join(DATA_DIR, "chat_history");
const BRIEFS_DIR = path.join(DATA_DIR, "briefs");
const HEAT_PATH = path.join(DATA_DIR, "heat_classification.json");

const OUR_UID = "2500000853693";
const READ_MSG_COUNT = 20; // 读取最近 N 条消息用于生成摘要

// ── 国家代码映射 ──────────────────────────────────────────
const COUNTRY_MAP = {
  US: "美国", GH: "加纳", CM: "喀麦隆", ZA: "南非", CD: "刚果民主共和国",
  CI: "科特迪瓦", ZM: "赞比亚", IQ: "伊拉克", SA: "沙特阿拉伯", AE: "阿联酋",
  SD: "苏丹", EG: "埃及", OM: "阿曼", BH: "巴林", KW: "科威特", QA: "卡塔尔",
  LB: "黎巴嫩", JO: "约旦", PS: "巴勒斯坦", SY: "叙利亚", YE: "也门",
  IN: "印度", PK: "巴基斯坦", UK: "英国", FR: "法国", DE: "德国",
  ES: "西班牙", IT: "意大利", NL: "荷兰", CA: "加拿大", AR: "阿根廷",
  TG: "多哥", KE: "肯尼亚", TZ: "坦桑尼亚", SN: "塞内加尔", RU: "俄罗斯",
  KZ: "哈萨克斯坦", UZ: "乌兹别克斯坦", JP: "日本", CN: "中国", HK: "香港",
  VN: "越南", IL: "以色列", VE: "委内瑞拉", BR: "巴西",
};

// ── 过滤黑名单 ──────────────────────────────────────────
const SKIP_NAMES = [
  "assistant eva", "assistanteva", // OKKI AI bot
  "leon scott kennedy", // obvious spam
];

const SKIP_KEYWORDS = ["鸭梨"]; // spam message content

function shouldSkip(result) {
  if (SKIP_NAMES.includes(result.name.toLowerCase().trim())) return true;
  for (const kw of SKIP_KEYWORDS) {
    if (result.lastMsgPreview && result.lastMsgPreview.includes(kw)) return true;
  }
  return false;
}

// ── 辅助 ──────────────────────────────────────────────────

function cidToFilename(cidStr) {
  const match = cidStr.match(/^(.+)#(\d+)@(\w+)$/);
  if (!match) return null;
  const [, left, channel, platform] = match;
  return `${left}_${channel}_${platform}.json`;
}

function safeFilename(name, cid) {
  // cid prefix + sanitized name
  const shortCid = cid.split("#")[0].replace(/[@.]/g, "_");
  const safeName = name.replace(/[\/\\:*?"<>|]/g, "-").replace(/\s+/g, "-");
  return `${shortCid}_${safeName}.md`;
}

function isSystemMessage(msg) {
  try {
    const ext = msg.message?.extension;
    if (ext?.systemMessage === true) return true;
    const bmi = ext?.basicMessageInfo;
    if (typeof bmi === "string" && bmi.includes('"systemMessage":true')) return true;
    return false;
  } catch { return false; }
}

function getMsgText(msg) {
  try { return msg.message?.content?.text?.content || ""; } catch { return ""; }
}

function getMsgTime(msg) {
  try { return msg.message?.createAt || 0; } catch { return 0; }
}

function senderIsUs(msg) {
  try { return (msg.message?.sender?.uid || "").includes(OUR_UID); } catch { return false; }
}

function getMsgId(msg) {
  try { return msg.message?.messageId || ""; } catch { return ""; }
}

function fmtDate(ts) {
  const d = new Date(ts);
  const pad = (n) => String(n).padStart(2, "0");
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

function fmtTime(ts) {
  const d = new Date(ts);
  const pad = (n) => String(n).padStart(2, "0");
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

// ── 判定阶段（基于聊天内容） ──────────────────────────────
function detectStage(messages) {
  const all = messages.map((m) => getMsgText(m).toLowerCase()).join(" ");
  if (/(payment|付款|deposit|定金|invoice|PI|proforma)/.test(all) && /(paid|付了|已付|done)/.test(all)) return "已成交（终态）";
  if (/(tracking|物流|shipment|shipped|已发货|提单|B\/L)/.test(all)) return "已发货/在途";
  if (/(ready|ready to ship|备好|ship.*soon|about to ship)/.test(all)) return "待发货";
  if (/(payment|付款|deposit|定金|balance|余款|pay)/i.test(all)) return "待付款";
  if (/(price|报价|usd|dollar|\$|单价|quotation|quote)/.test(all)) return "报价已发";
  if (/(sample|样品|打样)/.test(all)) return "样品阶段";
  if (/(negotiate|谈判|discount|折扣|better price|便宜)/.test(all)) return "谈判中";
  if (/(catalog|pattern|design|style|color|size)/.test(all)) return "需求探索";
  return "需求探索";
}

// ── 生成动态摘要 ──────────────────────────────────────────
function generateRecentSummary(realMsgs) {
  const recent = realMsgs.slice(0, Math.min(5, realMsgs.length));
  const lines = [];
  for (const msg of recent.reverse()) { // 时间正序
    const ts = getMsgTime(msg);
    const sender = senderIsUs(msg) ? "我" : "客";
