// ── 国家代码映射 ──────────────────────────────────────────
const COUNTRY_MAP = {
  US: "美国", GH: "加纳", CM: "喀麦隆", ZA: "南非", CD: "刚果民主共和国",
  CI: "科特迪瓦", ZM: "赞比亚", IQ: "伊拉克", SA: "沙特阿拉伯", AE: "阿联酋",
  SD: "苏丹", EG: "埃及", OM: "阿曼", BH: "巴林", KW: "科威特", QA: "卡塔尔",
  LB: "黎巴嫩", JO: "约旦", PS: "巴勒斯坦", SY: "叙利亚", YE: "也门",
  IN: "印度", PK: "巴基斯坦", UK: "英国", FR: "法国", DE: "德国",
  ES: "西班牙", IT: "意大利", NL: "荷兰", CA: "加拿大", AR: "阿根廷",
  TG: "多哥", KE: "肯尼亚", TZ: "坦桑尼亚", SN: "塞内加尔", RU: "俄罗斯",
  KZ: "哈萨克斯坦", UZ: "乌兹别克斯坦", JP: "日本", CN: "中国", HK: "香港",
  VN: "越南", IL: "以色列", VE: "委内瑞拉", BR: "巴西",
};

