#!/usr/bin/env node
/**
 * gen_dashboard.js — 从状态卡生成看板表格
 *
 * 读取 data/briefs/*.md，生成分组排序的客户看板。
 *
 * 用法:
 *   node scripts/gen_dashboard.js              → Markdown 表格到 stdout
 *   node scripts/gen_dashboard.js --html       → HTML 到 stdout
 *   node scripts/gen_dashboard.js -o board.md  → 输出到文件
 */

const fs = require("fs");
const path = require("path");

const DATA_DIR = path.resolve(__dirname, "..", "data");
const BRIEFS_DIR = path.join(DATA_DIR, "briefs");
const LATEST_PATH = path.join(DATA_DIR, "tm_conversations_latest.json");

const args = process.argv.slice(2);
const htmlMode = args.includes("--html");
const outFile = (() => {
  const idx = args.indexOf("-o");
  return idx >= 0 ? args[idx + 1] : null;
})();

// ── 解析 frontmatter ─────────────────────────────────────
function parseFrontmatter(content) {
  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!match) return {};
  const fm = {};
  for (const line of match[1].split("\n")) {
    const kv = line.match(/^(\w+):\s*(.+)$/);
    if (kv) fm[kv[1]] = kv[2].trim();
  }
  return fm;
}

// ── 从状态卡正文提取字段 ─────────────────────────────────

function extractSection(content, heading) {
  const re = new RegExp(`## ${heading}\\s*\\n([\\s\\S]*?)(?=\\n## |$)`, "i");
  const match = content.match(re);
  return match ? match[1].trim() : "";
}

function extractTalkSummary(content) {
