function openModal(cid) {
  const d = customers[cid];
  if (!d) return;
  let html = '';
  html += `<div class="modal-header"><h2>${d.name}</h2><button class="modal-close" onclick="closeModal()">✕</button></div>`;
  html += `<div class="modal-body">`;

  // Frontmatter
  html += `<div class="fm-grid">`;
  for (const [k,v] of [['国家',(d.country||'')],['阶段',d.stage],['最后联系',d.lastContact],['首次联系',d.firstContact]])
    html += `<div class="fm-item"><div class="fm-label">${k}</div><div class="fm-value">${v}</div></div>`;
  html += `</div>`;

  // Drivers
  if (d.drivers && d.drivers.length) {
    html += `<div class="section"><div class="section-title">📋 驱动因子</div><div class="driver-list">`;
    for (const dr of d.drivers) {
      const cls = dr.level==='red'?'driver-item-red':'driver-item-yellow';
      html += `<div class="driver-item ${cls}"><span class="driver-icon">${dr.level==='red'?'🔴':'🟡'}</span><div><strong>${dr.title}</strong><div style="color:#999;font-size:0.85em;margin-top:2px;">${dr.detail}</div></div></div>`;
    }
    html += `</div></div>`;
  }

  // Chat
  if (d.chat && d.chat.length) {
    html += `<div class="section"><div class="section-title">💬 聊到哪了</div><div class="chat-snippet">`;
    for (const cl of d.chat) {
      html += `<div class="chat-line"><span class="chat-who ${cl.who==='me'?'chat-who-me':'chat-who-cust'}">${cl.who==='me'?'我':'客'}</span><span class="chat-time">${cl.time}</span>${cl.text}</div>`;
    }
    html += `</div></div>`;
  }

  // Key numbers
  if (d.nums) {
    const nums = Array.isArray(d.nums) ? d.nums : [d.nums].filter(Boolean);
    if (nums.length) {
      html += `<div class="section"><div class="section-title">🔢 关键数字</div>`;
      for (const n of nums) html += `<div class="key-num">${n}</div>`;
      html += `</div>`;
    }
  }

  // Next step
  if (d.steps) {
    html += `<div class="section"><div class="section-title">→ 下一步</div><div style="font-size:0.88em;line-height:1.6;white-space:pre-line">${d.steps}</div></div>`;
  }

  html += `</div>`;
  html += `<div class="modal-footer"><button class="btn btn-primary">✏️ 起草回复</button><button class="btn">🔍 深度分析</button><button class="btn">✅ 标记已处理</button></div>`;

  document.getElementById('modal').innerHTML = html;
  document.getElementById('overlay').classList.add('show');
}

function closeModal() {
  document.getElementById('overlay').classList.remove('show');
}

document.addEventListener('keydown', e => { if (e.key==='Escape') closeModal(); });
</script>

</body>
</html>
